def has_cycle(graph):
    """Detects if there is a cycle in a directed graph represented as an adjacency list.

    Args:
        graph (dict): A dictionary where keys are nodes and values are lists of neighbor nodes.

    Returns:
        bool: True if a cycle is detected, False otherwise.
    """
    visited = set()
    rec_stack = set()

    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.remove(node)
        return False

    for node in graph:
        if node not in visited:
            if dfs(node):
                return True
    return False

