def has_cycle(graph):
    """Detects if a directed graph contains a cycle.

    Args:
        graph (dict): A dictionary representing the adjacency list of the graph,
                      where keys are nodes and values are lists of nodes they point to.

    Returns:
        bool: True if the graph contains a cycle, False otherwise.
    """
    visited = set()      # Set to track visited nodes.
    rec_stack = set()    # Set to track nodes in the current recursion stack.

    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
